{
    "level": "B2–C1",
    "intro": "In this topic, you will learn <strong>passive gerund</strong> in detail: how to form the simple (being done) and perfect (having been done) passive gerunds, when to use them and after which words they are used.",
    "rules": [
        {
            "label": "Simple",
            "color": "emerald",
            "text": "<strong>being + V3 (Past Participle)</strong> — simultaneous action:",
            "example": "She hates being interrupted."
        },
        {
            "label": "Perfect",
            "color": "blue",
            "text": "<strong>having been + V3</strong> — previous action:",
            "example": "Having been warned, he was careful."
        },
        {
            "label": "Comparison",
            "color": "rose",
            "text": "Active: <strong>doing / having done</strong> → Passive: <strong>being done / having been done</strong>",
            "example": "writing → being written → having been written"
        }
    ]
}

{
    "title": "1. Formation of the passive gerund",
    "intro": "Comparison of active and passive forms of the gerund:",
    "items": [
        {
            "label": "Active Simple",
            "title": "doing / writing",
            "subtitle": "I enjoy writing letters. - I like to write letters."
        },
        {
            "label": "Passive Simple",
            "title": "being done / being written",
            "subtitle": "He dislikes being criticized. - He doesn't like being criticized."
        },
        {
            "label": "Active Perfect",
            "title": "having done / having written",
            "subtitle": "Having finished the work, she left. — After finishing her work, she left."
        },
        {
            "label": "Passive Perfect",
            "title": "having been done / having been written",
            "subtitle": "Having been rejected, she tried again. — Having received a refusal, she tried again."
        }
    ]
}

{
    "title": "2. Simple passive gerund (being done)",
    "sections": [
        {
            "label": "After verbs of feelings",
            "color": "emerald",
            "description": "Після <strong>like, hate, enjoy, love, dislike, avoid, mind</strong>:",
            "examples": [
                {
                    "en": "She hates being interrupted.",
                    "ua": "She hates being interrupted."
                },
                {
                    "en": "Nobody likes being criticized.",
                    "ua": "Nobody likes being criticized."
                },
                {
                    "en": "He enjoys being praised.",
                    "ua": "He enjoys being praised."
                },
                {
                    "en": "I don't mind being asked questions.",
                    "ua": "I don't mind being asked questions."
                }
            ]
        },
        {
            "label": "After prepositions",
            "color": "blue",
            "description": "Після <strong>without, after, before, despite, instead of, on</strong>:",
            "examples": [
                {
                    "en": "He left without being noticed.",
                    "ua": "He left without being noticed."
                },
                {
                    "en": "After being rejected, she applied again.",
                    "ua": "After being rejected, she applied again."
                },
                {
                    "en": "Despite being warned, he continued.",
                    "ua": "Despite being warned, he continued."
                },
                {
                    "en": "Before being hired, she had to pass a test.",
                    "ua": "Before being hired, she had to pass a test."
                }
            ]
        },
        {
            "label": "After remember / forget / deny",
            "color": "amber",
            "description": "When the subject is the <strong>object of the action</strong>:",
            "examples": [
                {
                    "en": "I remember being told about it.",
                    "ua": "I remember being told about it."
                },
                {
                    "en": "She denies being involved.",
                    "ua": "She denies being involved."
                },
                {
                    "en": "He will never forget being helped by her.",
                    "ua": "He will never forget being helped by her."
                }
            ]
        }
    ]
}

{
    "title": "3. Perfect passive gerund (having been done)",
    "sections": [
        {
            "label": "Cause → effect",
            "color": "emerald",
            "description": "For actions that <strong>preceded others</strong> and became their cause:",
            "examples": [
                {
                    "en": "Having been warned, he was more careful.",
                    "ua": "Having been warned, he was more careful."
                },
                {
                    "en": "Having been told the truth, she felt relieved.",
                    "ua": "Having been told the truth, she felt relieved."
                },
                {
                    "en": "Having been rejected twice, he gave up.",
                    "ua": "Having been rejected twice, he gave up."
                }
            ]
        },
        {
            "label": "Formal style",
            "color": "blue",
            "description": "Often in <strong>academic and official</strong> writing:",
            "examples": [
                {
                    "en": "Having been approved by the board, the project will begin.",
                    "ua": "Having been approved by the board, the project will begin."
                },
                {
                    "en": "Having been elected, she took office immediately.",
                    "ua": "Having been elected, she took office immediately."
                },
                {
                    "en": "Having been tested, the product was released.",
                    "ua": "Having been tested, the product was released."
                }
            ]
        },
        {
            "label": "After prepositions",
            "color": "rose",
            "description": "To emphasize a <strong>previous action</strong>:",
            "examples": [
                {
                    "en": "After having been informed, he took action.",
                    "ua": "After having been informed, he took action."
                },
                {
                    "en": "Despite having been warned, she ignored the advice.",
                    "ua": "Despite having been warned, she ignored the advice."
                },
                {
                    "en": "On having been asked, he explained everything.",
                    "ua": "On having been asked, he explained everything."
                }
            ]
        }
    ]
}

{
    "title": "4. Words and expressions with the passive gerund",
    "sections": [
        {
            "label": "Verbs of feelings",
            "color": "emerald",
            "description": "<strong>like, love, hate, enjoy, dislike, prefer, avoid, mind, can't stand</strong>:",
            "examples": [
                {
                    "en": "I can't stand being ignored.",
                    "ua": "I can't stand being ignored."
                },
                {
                    "en": "She avoids being seen by him.",
                    "ua": "She avoids being seen by him."
                },
                {
                    "en": "They prefer being given clear instructions.",
                    "ua": "They prefer being given clear instructions."
                }
            ]
        },
        {
            "label": "Verbs of memory / speech",
            "color": "blue",
            "description": "<strong>remember, forget, deny, admit, recall, mention</strong>:",
            "examples": [
                {
                    "en": "He admitted being wrong.",
                    "ua": "He admitted being wrong."
                },
                {
                    "en": "She recalls being praised by her teacher.",
                    "ua": "She recalls being praised by her teacher."
                },
                {
                    "en": "He mentioned being offered a job.",
                    "ua": "He mentioned being offered a job."
                }
            ]
        },
        {
            "label": "Stable expressions",
            "color": "amber",
            "description": "<strong>be worth, be used to, look forward to, be afraid of</strong>:",
            "examples": [
                {
                    "en": "The book is worth being read.",
                    "ua": "The book is worth being read."
                },
                {
                    "en": "She is used to being watched.",
                    "ua": "She is used to being watched."
                },
                {
                    "en": "I'm afraid of being punished.",
                    "ua": "I'm afraid of being punished."
                }
            ]
        }
    ]
}

{
    "title": "5. Comparison: being done vs having been done",
    "intro": "When to use simple or perfect passive gerund:",
    "rows": [
        {
            "en": "being done",
            "ua": "being done",
            "note": "She hates being interrupted. - She hates being interrupted."
        },
        {
            "en": "having been done",
            "ua": "having been done",
            "note": "Having been warned, he was careful. — After receiving a warning, he was more careful."
        },
        {
            "en": "being done (прийменник)",
            "ua": "being done (прийменник)",
            "note": "Without being noticed, he left. - He left unnoticed."
        },
        {
            "en": "having been done (причина)",
            "ua": "having been done (причина)",
            "note": "Having been rejected, she tried again. — Having received a refusal, she tried again."
        }
    ],
    "warning": "📌 The perfect gerund emphasizes that the action happened BEFORE the main action in the sentence!"
}

{
    "title": "6. Comparison: Active vs Passive Gerund",
    "intro": "When the subject performs an action (active) or undergoes an action (passive):",
    "rows": [
        {
            "en": "Active: He likes helping others.",
            "ua": "Active: He likes helping others.",
            "note": "He (subject) helps."
        },
        {
            "en": "Passive: He likes being helped.",
            "ua": "Passive: He likes being helped.",
            "note": "He (subject) is helped."
        },
        {
            "en": "Active: I remember telling her.",
            "ua": "Active: I remember telling her.",
            "note": "I said"
        },
        {
            "en": "Passive: I remember being told.",
            "ua": "Passive: I remember being told.",
            "note": "I was told."
        }
    ],
    "warning": "📌 If the subject is the executor of the action — active gerund. If the subject undergoes action - passive gerund."
}

{
    "title": "7. Typical mistakes",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Omission of being in the passive gerund.",
            "wrong": "She hates criticized.",
            "right": "✅ She hates being criticized."
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Using V1 instead of V3.",
            "wrong": "He enjoys being praise.",
            "right": "✅ He enjoys being praised."
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Confusion of simple and perfect.",
            "wrong": "Being warned yesterday, he was careful.",
            "right": "✅ Having been warned yesterday, he was careful."
        },
        {
            "label": "Error 4",
            "color": "rose",
            "title": "Incorrect word order in the perfect tense.",
            "wrong": "been having done",
            "right": "✅ having been done"
        }
    ]
}
